import pytest
from your_module import hex_to_rgb  # Replace 'your_module' with actual module name


class TestHexToRgbHappyPath:
    """Tests for valid hex color inputs."""

    def test_standard_hex_color(self):
        """Test conversion of standard hex color."""
        assert hex_to_rgb("#FF5733") == (255, 87, 51)

    def test_lowercase_hex_color(self):
        """Test conversion of lowercase hex color."""
        assert hex_to_rgb("#ff5733") == (255, 87, 51)

    def test_mixed_case_hex_color(self):
        """Test conversion of mixed case hex color."""
        assert hex_to_rgb("#Ff57aB") == (255, 87, 171)

    def test_hex_without_hash(self):
        """Test hex color without leading hash."""
        assert hex_to_rgb("FF5733") == (255, 87, 51)

    def test_black_color(self):
        """Test conversion of black color."""
        assert hex_to_rgb("#000000") == (0, 0, 0)

    def test_white_color(self):
        """Test conversion of white color."""
        assert hex_to_rgb("#FFFFFF") == (255, 255, 255)

    def test_red_color(self):
        """Test conversion of pure red."""
        assert hex_to_rgb("#FF0000") == (255, 0, 0)

    def test_green_color(self):
        """Test conversion of pure green."""
        assert hex_to_rgb("#00FF00") == (0, 255, 0)

    def test_blue_color(self):
        """Test conversion of pure blue."""
        assert hex_to_rgb("#0000FF") == (0, 0, 255)

    def test_returns_tuple(self):
        """Test that return type is a tuple."""
        result = hex_to_rgb("#ABCDEF")
        assert isinstance(result, tuple)

    def test_tuple_length(self):
        """Test that returned tuple has exactly 3 elements."""
        result = hex_to_rgb("#ABCDEF")
        assert len(result) == 3

    def test_tuple_contains_integers(self):
        """Test that tuple contains only integers."""
        result = hex_to_rgb("#ABCDEF")
        assert all(isinstance(val, int) for val in result)


